// Me is the resolver for the me field.
func (r *queryResolver) Me(ctx context.Context) (*model.UserProfile, error) {
	req := request.ForContext(ctx)
	user := req.User()
	tenantIDs := user.TenantIDs()

	ids := make([]uuid.UUID, 0, len(tenantIDs))
	idsSet := make(map[uuid.UUID]struct{}, len(tenantIDs))

	for _, id := range tenantIDs {
		if _, ok := idsSet[id]; ok {
			continue
		}

		idsSet[id] = struct{}{}
		ids = append(ids, id)
	}

	dbTenantsMap := make(map[uuid.UUID]*ent.Tenant, len(ids))

	if len(ids) > 0 {
		tenants, err := r.client.Tenant.
			Query().
			Where(tenant.IDIn(ids...)).
			Select(tenant.FieldID, tenant.FieldName).
			All(ctx)
		if err != nil {
			return nil, err
		}

		for _, t := range tenants {
			dbTenantsMap[t.ID] = t
		}
	}

	userTenants := make([]*model.UserTenants, 0)
	userRoleTuples := make([]*model.UserRoleTuple, 0)

	for tenantID, role := range user.Roles {
		name := ""
		if t, ok := dbTenantsMap[tenantID]; ok && t != nil {
			name = t.Name
		}

		userRoleTuples = append(userRoleTuples, &model.UserRoleTuple{
			TenantID: tenantID,
			Role:     role.String(),
		})

		userTenants = append(userTenants, &model.UserTenants{
			ID:   tenantID,
			Name: name,
			Role: role.String(),
		})
	}

	tenantName := ""
	if t, ok := dbTenantsMap[user.TenantID]; ok && t != nil {
		tenantName = t.Name
	}

	result := model.UserProfile{
		Username:      user.Username,
		UserID:        user.ID,
		TenantID:      user.TenantID,
		TenantName:    tenantName,
		AssignedRoles: userRoleTuples,
		Tenants:       userTenants,
	}

	dbUser, err := r.client.User.Get(ctx, user.ID)
	if err == nil {
		result.Email = dbUser.Email
		result.FirstName = dbUser.FirstName
		result.LastName = dbUser.LastName
	}

	return &result, nil
}
